{"path": "Dockerfile", "content": "FROM php:8.2.30-fpm-trixie

# Basic setup and dependencies
ENV DEBIAN_FRONTEND=noninteractive

RUN apt-get update \
    && apt-get install -y --no-install-recommends \
        curl \
        unzip \
        git \
        zip \
        ca-certificates \
        nginx \
    && rm -rf /var/lib/apt/lists/*

# PHP extensions needed by most Laravel-like apps
RUN docker-php-ext-install pdo_mysql mbstring exif pcntl bcmath intl \
    && docker-php-ext-configure gd --with-freetype --with-jpeg \
    && apt-get update \
    && apt-get install -y --no-install-recommends libpng-dev libjpeg-dev libfreetype6-dev \
    && docker-php-ext-install -j$(nproc) gd \
    && rm -rf /var/lib/apt/lists/*

# Install Composer
RUN curl -sS https://getcomposer.org/installer | php -- --install-dir=/usr/local/bin --filename=composer

WORKDIR /var/www/coolify

# Copy composer files and install dependencies first (to leverage Docker cache)
COPY composer.json composer.lock ./
RUN composer install --no-dev --optimize-autoloader

# Copy the rest of the application code
COPY . /var/www/coolify/

# Ensure correct permissions for web server
RUN chown -R www-data:www-data /var/www/coolify

# Nginx configuration to serve the PHP-FPM backed app
RUN rm -f /etc/nginx/conf.d/default.conf
RUN bash -lc 'cat > /etc/nginx/conf.d/app.conf << "EOF" 
server {
    listen 80;
    server_name localhost;
    root /var/www/coolify/public;
    index index.php;

    access_log /var/log/nginx/access.log;
    error_log /var/log/nginx/error.log;

    location / {
        try_files $uri $uri/ /index.php?$query_string;
    }

    location ~ \.php$ {
        try_files $uri =404;
        # PHP-FPM by TCP
        fastcgi_pass 127.0.0.1:9000;
        fastcgi_index index.php;
        include fastcgi_params;
        fastcgi_param SCRIPT_FILENAME $document_root$fastcgi_script_name;
    }

    location ~ /\.well-known/ {
        allow all;
    }

    location ~ \.[^/]+$ {
        expires 1y;
        access_log off;
    }
}
EOF'

# Expose port
EXPOSE 80

# Run both PHP-FPM and Nginx in the container
CMD ["bash","-lc","php-fpm -D && nginx -g 'daemon off;'"]
"}
